global.schema:
type LeadFunnelState {
  name: String!
  leads: [Lead!]!
}

type Lead {
  id: OID!
  name: String!
  company: String
  clientId: OID
  email: EmailAddress
  phone: String
  source: LeadSource!
  stage: LeadStage!
  priority: LeadPriority!
  estimatedValue: Amount_Money
  owner: String
  score: Int!
  tags: [String!]!
  notes: String
  activities: [Activity!]!
  createdAt: DateTime!
  updatedAt: DateTime!
}

type Activity {
  id: OID!
  type: ActivityType!
  note: String
  timestamp: DateTime!
}

enum LeadStage { NEW CONTACTED QUALIFIED PROPOSAL NEGOTIATION WON LOST }

enum LeadSource { WEBSITE REFERRAL COLD_OUTREACH EVENT SOCIAL OTHER }

enum LeadPriority { LOW MEDIUM HIGH }

enum ActivityType { CALL EMAIL MEETING NOTE }

operations.reducer:
const lead = state.leads.find((l) => l.id === action.input.id);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.id} not found`);
}
if (action.input.name) lead.name = action.input.name;
if (action.input.company) lead.company = action.input.company;
if (action.input.email) lead.email = action.input.email;
if (action.input.phone) lead.phone = action.input.phone;
if (action.input.source) lead.source = action.input.source;
if (action.input.priority) lead.priority = action.input.priority;
if (action.input.estimatedValue) lead.estimatedValue = action.input.estimatedValue;
if (action.input.owner) lead.owner = action.input.owner;
if (action.input.score !== undefined && action.input.score !== null) lead.score = action.input.score;
if (action.input.notes) lead.notes = action.input.notes;
lead.updatedAt = action.input.updatedAt;

operations.schema:
input MoveLeadInput {
  id: OID!
  stage: LeadStage!
  updatedAt: DateTime!
}

operations.reducer:
const lead = state.leads.find((l) => l.id === action.input.id);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.id} not found`);
}
lead.stage = action.input.stage;
lead.updatedAt = action.input.updatedAt;

operations.schema:
input ReorderLeadInput {
  id: OID!
  targetIndex: Int!
}

operations.reducer:
const currentIndex = state.leads.findIndex((l) => l.id === action.input.id);
if (currentIndex === -1) {
  throw new LeadNotFoundError(`Lead with id ${action.input.id} not found`);
}
const [lead] = state.leads.splice(currentIndex, 1);
const target = Math.max(0, Math.min(action.input.targetIndex, state.leads.length));
state.leads.splice(target, 0, lead);

const index = state.leads.findIndex((l) => l.id === action.input.id);
if (index === -1) {
  throw new LeadNotFoundError(`Lead with id ${action.input.id} not found`);
}
state.leads.splice(index, 1);

const lead = state.leads.find((l) => l.id === action.input.leadId);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.leadId} not found`);
}
if (lead.activities.some((a) => a.id === action.input.id)) {
  throw new DuplicateActivityIdError(`Activity with id ${action.input.id} already exists`);
}
lead.activities.push({
  id: action.input.id,
  type: action.input.type,
  note: action.input.note || null,
  timestamp: action.input.timestamp,
});
lead.updatedAt = action.input.timestamp;

operations.schema:
input DeleteActivityInput {
  leadId: OID!
  id: OID!
  timestamp: DateTime!
}

operations.reducer:
const lead = state.leads.find((l) => l.id === action.input.leadId);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.leadId} not found`);
}
const index = lead.activities.findIndex((a) => a.id === action.input.id);
if (index === -1) {
  throw new ActivityNotFoundError(`Activity with id ${action.input.id} not found`);
}
lead.activities.splice(index, 1);
lead.updatedAt = action.input.timestamp;

operations.schema:
input AddTagInput {
  leadId: OID!
  tag: String!
}

operations.reducer:
const lead = state.leads.find((l) => l.id === action.input.leadId);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.leadId} not found`);
}
if (lead.tags.includes(action.input.tag)) {
  throw new DuplicateTagError(`Tag ${action.input.tag} already exists on this lead`);
}
lead.tags.push(action.input.tag);

operations.schema:
input RemoveTagInput {
  leadId: OID!
  tag: String!
}

operations.reducer:
const lead = state.leads.find((l) => l.id === action.input.leadId);
if (!lead) {
  throw new LeadNotFoundError(`Lead with id ${action.input.leadId} not found`);
}
const index = lead.tags.indexOf(action.input.tag);
if (index === -1) {
  throw new TagNotFoundError(`Tag ${action.input.tag} not found on this lead`);
}
lead.tags.splice(index, 1);
